using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 25.50m, Quantity = 1 },
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.AreEqual(45.50m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCustomerId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _sut.CreateOrder("customer-42", items);

        // Assert
        Assert.AreEqual("customer-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.UtcNow;
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert
        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };

        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        // Act & Assert
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("customer-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        // Arrange
        var items = new List<OrderItem>();

        // Act & Assert
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("customer-1", items));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsMatchingOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 10.00m, Quantity = 1 },
        };
        var created = _sut.CreateOrder("customer-1", items);

        // Act
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        // Act
        var result = _sut.GetOrder("non-existent-id");

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithMatchingOrders_ReturnsAllCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 5.00m, Quantity = 1 },
        };
        _sut.CreateOrder("customer-A", items);
        _sut.CreateOrder("customer-A", items);
        _sut.CreateOrder("customer-B", items);

        // Act
        var orders = _sut.GetOrdersByCustomer("customer-A");

        // Assert
        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoMatchingOrders_ReturnsEmptyList()
    {
        // Act
        var orders = _sut.GetOrdersByCustomer("unknown-customer");

        // Assert
        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_CalculatesTotalCorrectly()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "A", Price = 3.50m, Quantity = 4 },
            new() { ProductName = "B", Price = 12.00m, Quantity = 2 },
            new() { ProductName = "C", Price = 0.99m, Quantity = 10 },
        };

        // Act
        var order = _sut.CreateOrder("customer-1", items);

        // Assert — (3.50*4) + (12.00*2) + (0.99*10) = 14 + 24 + 9.90 = 47.90
        Assert.AreEqual(47.90m, order.Total);
    }
}

